using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Text;
using System.Text.Json;
using System.Threading.Tasks;

namespace TestWebhook
{
    internal class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("Generating HTTP POST request...");
            TestHttpPOST().GetAwaiter().GetResult();
            Console.WriteLine("HTTP POST request generated.");
        }


        public static async Task TestHttpPOST()
        {
            var url = "https://replace-with-actual-wephook-end-pint";

            var client = new HttpClient();
            // Add API key header
            client.DefaultRequestHeaders.Add("x-api-key", "paste-api-key-here");

            // Build JSON payload
            var payload = new WebhookPayload
            {
                Timestamp = "2026-03-18T12=52=35.7411065-07=00",
                WebhookNotificationId = "36451",
                MessageVersion = "1.1.0",
                Message = new WebhookMessage
                {
                    TXTBase64 = "",
                    UtilityID = "33313",
                    UtilityName = "COUNTY OF GRANDE PRAIRIE NO. 1",
                    StationCode = "CGRAND",
                    TicketNumber = "20261200054-000",
                    SequenceNumber = "4",
                    RequestDate = "2026-03-18T13=51=57.90996-06=00",
                    XMLBase64 = "",
                    GMLBase64 = "",
                    GIFBase64 = ""
                }
            };

            var json = JsonSerializer.Serialize(payload);
            var content = new StringContent(json, Encoding.UTF8, "application/json");

            // Send POST
            var response = await client.PostAsync(url, content);

            // Read response
            var result = await response.Content.ReadAsStringAsync();
            Console.WriteLine(result);
        }
    }
}
